// =============================================================
// Node-RED Function Node: "1. Lookup Bin Mapping"
// TrashTrack - Sprint 2 - Node-RED Data Pipeline Bridge
//
// CARA PAKAI DI NODE-RED:
// 1. Buat node Function baru, beri nama "1. Lookup Bin Mapping"
// 2. Copy seluruh isi file ini ke tab "On Message"
// 3. Sambungkan setelah node "JSON Parse" (sebelum node transform)
//
// FUNGSI:
// simulator.py mengirim "bin_id" bergaya BIN-Z1-01 (per zona simulasi),
// sedangkan tabel trash_bins di Laravel (lihat database/seeders/
// TrashBinSeeder.php) memakai bin_code & id auto-increment yang
// berbeda format (BIN-MNT-001, BIN-KBY-001, dst).
//
// Supaya pipeline bisa jalan end-to-end tanpa mengubah simulator
// maupun seeder Laravel, kita map tiap "zone" simulator ke SATU
// trash_bin_id yang valid & sudah ada di database Laravel.
//
// PENTING: Sesuaikan pemetaan ini dengan trash_bin_id yang BENAR
// ada di database Anda. Jalankan query berikut di Laravel untuk
// memastikan:
//
//   php artisan tinker
//   >>> \App\Models\TrashBin::select('id','bin_code')->get();
//
// Lalu sesuaikan ZONE_TO_BIN di bawah ini (trash_bin_id WAJIB
// cocok dengan kolom "id" di tabel trash_bins; capacity_liters
// dipakai node selanjutnya untuk mengonversi fill_level % menjadi
// distance_cm, jadi harus sama dengan kolom capacity_liters bin
// tersebut di database).
// =============================================================

// id & capacity_liters HARUS sama dengan baris di
// database/seeders/TrashBinSeeder.php (urutan insert = urutan id 1..N)
const ZONE_TO_BIN = {
    zone1: { trash_bin_id: 1, capacity_liters: 100 },
    zone2: { trash_bin_id: 2, capacity_liters: 80 },
    zone3: { trash_bin_id: 3, capacity_liters: 120 },
    zone4: { trash_bin_id: 4, capacity_liters: 100 },
    zone5: { trash_bin_id: 5, capacity_liters: 150 },
};

const raw = msg.payload;

// Validasi payload dasar dari simulator.py / Wokwi
if (!raw || !raw.zone || !raw.bin_id || raw.fill_level === undefined) {
    node.warn("Payload tidak lengkap, di-skip: " + JSON.stringify(raw));
    return null;
}

const binInfo = ZONE_TO_BIN[raw.zone];

if (!binInfo) {
    node.warn(`Zone "${raw.zone}" tidak terdaftar di ZONE_TO_BIN, payload di-skip.`);
    return null;
}

// Simpan hasil lookup ke msg, dipakai oleh node
// "2. Transform Payload" berikutnya. msg.payload tidak diubah
// dulu di sini supaya data mentah masih bisa dipakai/didebug.
msg.trash_bin_id = binInfo.trash_bin_id;
msg.capacity_liters = binInfo.capacity_liters;

return msg;

// =============================================================
// Node-RED Function Node: "2. Transform Payload"
// TrashTrack - Sprint 2 - Node-RED Data Pipeline Bridge
//
// CARA PAKAI DI NODE-RED:
// 1. Buat node Function baru, beri nama "2. Transform Payload"
// 2. Copy seluruh isi file ini ke tab "On Message"
// 3. Sambungkan setelah node "1. Lookup Bin Mapping"
//    dan SEBELUM node "HTTP Request" (POST ke gateway)
//
// FUNGSI:
// Catatan penting: skema field di dokumen Sprint 2 (zone_id, gas_ppm,
// bin_status, dst.) TIDAK sesuai dengan kontrak asli yang divalidasi
// backend/app/Http/Requests/StoreTelemetryRequest.php. Validator
// Laravel itu sebenarnya mewajibkan field: trash_bin_id, distance_cm,
// methane_ppm, temperature_c, raw_payload (opsional). Function node
// ini mengikuti kontrak ASLI di kode Laravel, bukan dokumen.
//
// Konversi fill_level (%) -> distance_cm mengikuti rumus kebalikan
// dari IoTReceiverController::storeTelemetry():
//   volumePct   = ((tinggi_cm - distance_cm) / tinggi_cm) * 100
//   distance_cm = tinggi_cm * (1 - volumePct / 100)
// dengan asumsi tinggi_cm = capacity_liters (1 liter = 1 cm tinggi,
// sesuai komentar di IoTReceiverController.php).
// =============================================================

const raw = msg.payload;
const trashBinId = msg.trash_bin_id;
const capacityLiters = msg.capacity_liters;

if (!trashBinId || !capacityLiters) {
    node.warn("trash_bin_id / capacity_liters belum ada di msg. " +
        "Pastikan node '1. Lookup Bin Mapping' berjalan sebelum node ini.");
    return null;
}

// Konversi fill_level (%) menjadi distance_cm (kebalikan rumus Laravel)
const binHeightCm = capacityLiters; // asumsi 1 liter = 1 cm tinggi
let distanceCm = binHeightCm * (1 - raw.fill_level / 100);
distanceCm = Math.max(0, Math.min(400, distanceCm)); // sesuai rule "min:0|max:400"
distanceCm = Math.round(distanceCm * 100) / 100;

// Body sesuai StoreTelemetryRequest.php
msg.payload = {
    trash_bin_id: trashBinId,
    distance_cm: distanceCm,
    methane_ppm: raw.gas_level,
    temperature_c: raw.temperature,
    // raw_payload disimpan utuh di Laravel (kolom JSON) untuk audit/debug,
    // berisi payload asli dari simulator.py / Wokwi
    raw_payload: raw,
};

// Header untuk HTTP Request node (Authorization di-set oleh node
// "Get OAuth Token" sebelumnya lewat msg.headers, jadi di sini
// kita hanya pastikan Content-Type ikut terkirim)
msg.headers = Object.assign({}, msg.headers, {
    "Content-Type": "application/json",
});

return msg;

// =============================================================
// Node-RED Function Node: "3. Check Token Cache"
// TrashTrack - Sprint 2 - Node-RED Data Pipeline Bridge
//
// CARA PAKAI DI NODE-RED:
// 1. Buat node Function baru, beri nama "3. Check Token Cache"
// 2. Copy seluruh isi file ini ke tab "On Message"
// 3. Set "Outputs" node ini jadi 1 (default)
// 4. Sambungkan node ini SETELAH "2. Transform Payload"
// 5. Keluaran node ini dicabangkan ke node Switch:
//    - msg.needNewToken === true  -> ke node "Get OAuth Token" (HTTP Request)
//    - msg.needNewToken === false -> langsung ke node "HTTP Request ke Gateway"
//    (gunakan node "Switch" dengan 2 rule berdasarkan msg.needNewToken)
//
// FUNGSI:
// Token JWT dari oauth-server berlaku 1 jam (JWT_EXPIRES_IN=1h).
// Supaya Node-RED tidak minta token baru setiap kali ada data MQTT
// masuk (tiap 30 detik x 4 zona = boros & membebani oauth-server),
// token disimpan di flow context dan dipakai ulang sampai mendekati
// expired (kita beri buffer 60 detik sebelum benar-benar expired).
// =============================================================

const cachedToken = flow.get("iot_access_token");
const expiresAt = flow.get("iot_token_expires_at") || 0;
const now = Date.now();
const SAFETY_BUFFER_MS = 60 * 1000; // minta token baru 60 detik sebelum expired

if (cachedToken && now < (expiresAt - SAFETY_BUFFER_MS)) {
    // Token masih valid, langsung pakai dari cache
    msg.headers = Object.assign({}, msg.headers, {
        Authorization: "Bearer " + cachedToken,
    });
    msg.needNewToken = false;
} else {
    msg.needNewToken = true;
}

return msg;

// =============================================================
// Node-RED Function Node: "4. Prepare Token Request"
// TrashTrack - Sprint 2 - Node-RED Data Pipeline Bridge
//
// CARA PAKAI DI NODE-RED:
// 1. Buat node Function baru, beri nama "4. Prepare Token Request"
// 2. Copy seluruh isi file ini ke tab "On Message"
// 3. Sambungkan dari cabang "needNewToken === true" (lihat node
//    Switch setelah "3. Check Token Cache")
// 4. Setelah node ini, sambungkan ke node "HTTP Request" yang
//    method-nya POST, URL = env.OAUTH_URL (gunakan node
//    "Get OAuth Token")
//
// FUNGSI:
// Menyiapkan msg.payload & msg.headers untuk request
// POST /oauth/token dengan grant_type=client_credentials,
// memakai kredensial client "iot-device" (lihat
// oauth-server/src/models/tokenStore.js).
//
// PENTING: msg asli (payload telemetry yang sudah ditransform)
// disimpan dulu ke msg._originalMsg supaya tidak hilang — nanti
// dikembalikan oleh node "5. Store Token & Resume" setelah token
// baru diterima.
// =============================================================

// Simpan payload telemetry asli supaya tidak tertimpa
msg._originalPayload = msg.payload;
msg._originalHeaders = msg.headers;

msg.payload = {
    grant_type: "client_credentials",
    client_id: env.get("OAUTH_CLIENT_ID") || "iot-device",
    client_secret: env.get("OAUTH_CLIENT_SECRET") || "iot-secret",
    scope: "service",
};

msg.headers = {
    "Content-Type": "application/json",
};

return msg;

// =============================================================
// Node-RED Function Node: "5. Store Token & Resume"
// TrashTrack - Sprint 2 - Node-RED Data Pipeline Bridge
//
// CARA PAKAI DI NODE-RED:
// 1. Buat node Function baru, beri nama "5. Store Token & Resume"
// 2. Copy seluruh isi file ini ke tab "On Message"
// 3. Sambungkan SETELAH node HTTP Request "Get OAuth Token"
//    (response dari POST /oauth/token)
// 4. Setelah node ini, sambungkan ke node "HTTP Request ke Gateway"
//    (yang sama dengan yang dipakai oleh cabang token-dari-cache)
//
// FUNGSI:
// 1. Menyimpan access_token baru ke flow context (dipakai lagi oleh
//    node "3. Check Token Cache" di siklus berikutnya).
// 2. Mengembalikan msg.payload ke payload telemetry ASLI (yang sempat
//    disimpan ke msg._originalPayload oleh node
//    "4. Prepare Token Request"), supaya tidak hilang tertimpa
//    response oauth-server.
// =============================================================

const body = msg.payload; // response dari POST /oauth/token

if (!body || body.status !== "success" || !body.data || !body.data.access_token) {
    node.error("Gagal mendapatkan token dari OAuth server: " + JSON.stringify(body));
    return null;
}

const accessToken = body.data.access_token;
const expiresInSec = body.data.expires_in || 3600;
const expiresAt = Date.now() + expiresInSec * 1000;

// Simpan ke flow context untuk dipakai ulang oleh pesan-pesan berikutnya
flow.set("iot_access_token", accessToken);
flow.set("iot_token_expires_at", expiresAt);

node.log(`Token IoT baru diperoleh, berlaku ${expiresInSec} detik.`);

// Kembalikan payload telemetry yang sempat disimpan, lalu pasang
// header Authorization dengan token yang baru saja diterima
msg.payload = msg._originalPayload;
msg.headers = Object.assign({}, msg._originalHeaders, {
    Authorization: "Bearer " + accessToken,
});

delete msg._originalPayload;
delete msg._originalHeaders;

return msg;

// =============================================================
// Node-RED Function Node: "6. Check Response & Retry"
// TrashTrack - Sprint 2 - Node-RED Data Pipeline Bridge
//
// CARA PAKAI DI NODE-RED:
// 1. Buat node Function baru, beri nama "6. Check Response & Retry"
// 2. Copy seluruh isi file ini ke tab "On Message"
// 3. Sambungkan SETELAH node HTTP Request ke Gateway
//    (POST /iot/telemetry)
// 4. Set "Outputs" node ini jadi 2:
//    Output 1 -> ke node Debug "Sukses"
//    Output 2 -> ke node Delay "Retry 60s" lalu balik lagi ke
//                node HTTP Request ke Gateway
//
// FUNGSI:
// Sesuai requirement dokumen Sprint 2 (§3.4 Error Handling Node-RED):
// - Jika HTTP Gateway mengembalikan 502/503 (upstream/gateway down),
//   data TIDAK dibuang, tapi dikirim ke jalur retry.
// - msg.retryCount dihitung supaya tidak retry selamanya (maks 5x,
//   bisa disesuaikan).
// - Status code 200/201 dianggap sukses.
// =============================================================

const statusCode = msg.statusCode;
const MAX_RETRY = 5;

msg.retryCount = (msg.retryCount || 0) + 1;

if (statusCode === 200 || statusCode === 201) {
    node.status({ fill: "green", shape: "dot", text: "OK " + statusCode });
    return [msg, null]; // output 1: sukses
}

// Retry hanya untuk error upstream/gateway (data sensor tetap valid,
// hanya gateway/backend yang sedang tidak tersedia)
const isRetryableError = statusCode === 502 || statusCode === 503 || statusCode === undefined;

if (isRetryableError && msg.retryCount <= MAX_RETRY) {
    node.warn(`Gateway tidak tersedia (status=${statusCode}), retry ke-${msg.retryCount} dalam 60 detik...`);
    node.status({ fill: "yellow", shape: "ring", text: `retry ${msg.retryCount}/${MAX_RETRY}` });
    return [null, msg]; // output 2: retry
}

// Error selain itu (mis. 401/422 — token salah / validasi gagal)
// atau sudah melebihi batas retry -> jangan retry lagi, cukup log
node.error(`Gagal kirim telemetry setelah ${msg.retryCount} percobaan, status=${statusCode}: ` +
    JSON.stringify(msg.payload));
node.status({ fill: "red", shape: "dot", text: "FAILED " + statusCode });
return [null, null];
